var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くうっ……！","ENG":"Krgh...!","TWN":"呃……!"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네를 습격했던 수많은 침식체들을 기억하나?","JPN":"君を襲った多くの侵食体を覚えているかね？","ENG":"Do you remember all the C.O.s that attacked you?","TWN":"還記得襲擊你的那些侵蝕體嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"바로 변이조차 하지 못하고 도태된 자들의 말로지.","JPN":"変異すらできず淘汰された者たちの成れの果てだ。","ENG":"They were the ones who failed to mutate and were simply discarded.","TWN":"這就是那些連變異都沒能完成，就被淘汰的人的下場。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"그들이 노리는 건 단 한 가지일세.","JPN":"彼らが狙っているのはただ一つ。","ENG":"They only sought one thing.","TWN":"他們的目標只有一個。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"그자들에겐 없었던, 완성에 가까운 자네의 인자지.","JPN":"自分たちにはなかった、完成品に近い君のファクターさ。","ENG":"Something they lacked. The perfected factor within you.","TWN":"就是那些人所沒有的，你那接近完美的因子。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 침식체들도 줄 서서 돈 내라 그래!","JPN":"じゃあ、侵食体も並んで金を払えっての！","ENG":"Then they better line up and pay for it!","TWN":"那就讓侵蝕體們也排隊交錢吧！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"머리통을 하나씩 박살 내줄 테니까!","JPN":"頭を1匹ずつぶち壊してやるから！","ENG":"I'll crush every single one of them, one by one!","TWN":"我要一個個地打爆你們的腦袋！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"윽……!","JPN":"うっ……！","ENG":"Ugh...!","TWN":"呃……!"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"불량식품!","JPN":"お菓子さん！","ENG":"Junk food!","TWN":"垃圾食物！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"내가 연구를 시작한 이후 가장 먼저 시작한 것이 무엇인지 아나?","JPN":"私が研究を始めて、一番最初にしたことが何かわかるかね？","ENG":"Do you know what the very first step in my research was?","TWN":"你知道我在開始研究後最先做的是什麼嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"바로 자네 같은 감염자들의 약점을 알아내는 것이었네.","JPN":"君のような感染者たちの弱点を調べることだったよ。","ENG":"Figuring out the weaknesses of the afflicted like you.","TWN":"就是要找出像你這樣的感染者的弱點。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"은탄, 햇빛 등…… 유용한 방법들을 구비해뒀지.","JPN":"銀の弾、太陽の光……あらゆる有効な手段を用意している。","ENG":"Silver bullets, sunlight... I made sure to equip myself with all the necessary tools.","TWN":"銀彈、陽光等……我準備了很多有用的方法。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"언젠가 마주하게 될 이상 침식 현상을 일으킨 존재를 연구하기 위해서!","JPN":"いつか向き合うであろう、異常侵食現象を起こした存在を研究するために！","ENG":"To study the one who caused the Aberrant Counterside Effect, of course.","TWN":"為了研究某天會遇到的引發異常侵蝕現象的存在！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"역시 힘을 쓸 수 없었던 건 단순히 침식파 때문이 아니었어…….","JPN":"やっぱり力が使えなかったのは、侵食波のせいだけじゃなかったんだ……","ENG":"So that's why I couldn't use my full strength... It wasn't just the Corruption rays...","TWN":"果然無法使用力量不僅僅是因為侵蝕波……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 저 자식들을 힘겹게 상대했던 것도…….","JPN":"じゃあ、あいつらと戦うのに苦労したのも……","ENG":"That explains why I struggled against those things...","TWN":"那麼，之前和那些傢伙的辛苦對抗也是……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"수많은 실패작을 연구하면서 햇빛이 그들에게 어떻게 작용하는지 알아보았네.","JPN":"数多の失敗作を研究しながら、太陽の光が彼らにどう作用するか調べた。","ENG":"Through countless failed experiments, I learned how sunlight affects them.","TWN":"在研究了無數失敗品之後，我發現陽光是如何對他們起作用的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"햇빛이 활성화된 인자와 세포에 치명적인 작용을…….","JPN":"太陽光は、活性化したファクターと細胞に致命的な影響を……","ENG":"Sunlight is deadly to activated factors and mutated cells...","TWN":"陽光對活化的因子和細胞產生致命的作用……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"내가 힘을 쓰지 못하도록 수작질했다는 거잖아.","JPN":"私が力をまともに出せないように小細工をしたってことじゃないか。","ENG":"So you set me up from the start to weaken me.","TWN":"現在就是說你耍了什麼手段讓我無法使用力量不是嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그냥 닥쳐. 거슬리니까.","JPN":"もう黙れ。いい加減耳障りだ。","ENG":"Just shut up. You're getting on my nerves.","TWN":"閉嘴，你好吵。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네들에겐 승산이 없네.","JPN":"君たちに勝ち目はない。","ENG":"You have no chance of winning.","TWN":"你們是沒有勝算的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L38_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"창백한 달 감염자와 함께 연구에 협조하게나.","JPN":"青白い月の感染者と共に、私の研究に協力したまえ。","ENG":"You and the Pale Moon afflicted, accept your fate and cooperate with my research.","TWN":"請與蒼月感染者一起合作研究。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"고통스럽진 않을 걸세. 대부분은 의식을 잃은 채 실험에 참여할 테니.","JPN":"苦しくはないはずだ。ほとんどは意識を失った状態で実験に参加することになる。","ENG":"It won't be painful. You'll be unconscious for most of the experiments.","TWN":"不會痛苦的。大多數人都會在失去意識的情況下參與實驗。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"나는 직업 윤리를 썩 잘 지키는 편이거든.","JPN":"私は研究倫理をきっちり守るほうでね。","ENG":"I pride myself on my professional ethics, after all.","TWN":"我可是很遵守職業操守的喔。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"헛소리 마시죠.","JPN":"ふざけないでください。","ENG":"Spare me your nonsense.","TWN":"少胡說八道。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"주님의 분노가 두렵지도 않나요?","JPN":"主の怒りが怖くないのですか？","ENG":"Do you not fear the wrath of the Lord?","TWN":"你不怕主的憤怒嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"붉은 달이 떠올랐을 때, 사람들은 모두 광기에 휩싸여 서로를 죽이기에 바빴네.","JPN":"赤い月が昇った時、人々は皆狂気にのまれ、互いを殺し合った。","ENG":"When the Red Moon rose, people were consumed by madness, slaughtering each other in the streets.","TWN":"當紅月升起時，人們都陷入了瘋狂，忙著互相殘殺。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"진정으로 신을 믿는 신자라면 대답해 주게.","JPN":"真に神を信じる者なら答えてくれ。","ENG":"If you're truly a believer, answer me this.","TWN":"如果你是真正的信徒，請回答我。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"왜 그날 신은 우리에게 아무런 도움도 주지 못했나?","JPN":"なぜその日、神は我々を助けなかったのか？","ENG":"Why did your god do nothing that day?","TWN":"為什麼那天神沒有給我們任何幫助？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That's...","TWN":"那個……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"대답하지 못하겠지.","JPN":"答えられないだろう。","ENG":"You can't answer, can you?","TWN":"你無法回答吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"자네도 내심 신을 원망하고 있을 테니.","JPN":"何故なら、君も心のどこかでは神を恨んでいるはずだから。","ENG":"Deep down, you resent Him too.","TWN":"你心裡也在埋怨神吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"윽…….","JPN":"うっ……","ENG":"Ngh...","TWN":"呃……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"야, 그 이상한 책으로 저 녀석을 봉인할 수는 없어?","JPN":"ちょっと、その変な本であいつを封印したりできないの？","ENG":"Hey, can't you use that weird book of yours to seal him or something?","TWN":"喂，不能用那本奇怪的書封印那傢伙嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……저도 마음은 굴뚝 같지만 불가능해요.","JPN":"……そうしたい気持ちは山々ですが、できません。","ENG":"...I'd love to, but no. It's impossible.","TWN":"……我也很想這麼做，但不可能。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 책이 어떻게 작동하는지……. 저도 잘 모르거든요.","JPN":"この本がどういう原理で動くのか……私もよくわからないんです。","ENG":"I don't even fully understand... how this book works.","TWN":"這本書是如何運作的……我也不太清楚。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"쳇, 쓸모없어.","JPN":"ちっ、役立たず。","ENG":"Tch, useless.","TWN":"嘖，真沒用。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"당신이 실험용 쥐가 되는 걸 막아줬잖아요?!","JPN":"あなたが実験用のネズミにならないように助けてあげたじゃないですか！","ENG":"I just saved you from becoming a lab rat, you know?!","TWN":"是我讓你不用成為實驗用的白老鼠欸？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 맛있는 것 빼곤 할 줄 아는 게 없는 불량식품!","JPN":"この、美味しい以外なんの取り柄もないお菓子！","ENG":"You're nothing but a useless Junk food that tastes good!","TWN":"你真是個除了好吃，但什麼都不會的垃圾食物！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 여기서 아무것도 못 하고 당할 수는 없잖아.","JPN":"でも、このまま何もしないでやられるわけにはいかない。","ENG":"But we can't just sit here and do nothing.","TWN":"那也不能在這裡什麼都不做地等死吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"야, 저택을 나가기만 하면, 성황청의 지원이든 뭐든 불러올 수 있는 거지?","JPN":"おい、邸宅の外に出られれば、聖皇庁の支援でも何でも呼べるんだろう？","ENG":"If we can make it out of the estate, we can call for backup from the Holy Curia, right?","TWN":"喂，只要離開這座屋子，就能召喚聖皇廳的支援什麼的吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저, 저요? 장담할 수는 없지만 가능할 거예요.","JPN":"わ、私がですか？　うーん……たぶん、できます。","ENG":"M-me? I can't guarantee it, but it's possible.","TWN":"我，我嗎？雖然不能保證，但應該可以。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 이거 받아.","JPN":"じゃあこれ受け取って。","ENG":"Then take this.","TWN":"那你接住這個。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이건…… 무전기잖아요?","JPN":"これは……無線機？","ENG":"...A radio?","TWN":"這個……是對講機吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};